export const generatePovSegments = async (
  analysis: string, 
  style: string, 
  count: number, 
  gender: string, 
  voice: string, 
  charDesc: string, 
  contextNote: string
): Promise<string[]> => {
  const ai = getAiClient();

  let dialectInstruction = "";
  if (voice === 'Miền Bắc') {
    dialectInstruction = `
      NGÔN NGỮ CHUẨN NGƯỜI HÀ NỘI (MIỀN BẮC):
      - Dùng các từ đệm: "nhé", "ạ", "thế", "đấy", "chứ", "không", "vẫn".
      - TUYỆT ĐỐI KHÔNG dùng: nha, nè, hông, thiệt.
    `;
  } else {
    dialectInstruction = `
      NGÔN NGỮ CHUẨN NGƯỜI SÀI GÒN (MIỀN NAM):
      - Dùng các từ đệm: "nha", "nè", "nghen", "hen", "đó", "vầy".
      - Cách dùng từ: "hông" (không), "thiệt" (thật).
      - TUYỆT ĐỐI KHÔNG dùng: nhé, ạ, thế, đấy.
    `;
  }

  const prompt = `
    Dựa trên bản phân tích nội dung sau: "${analysis}".
    Hãy tạo ra một kịch bản POV mới hoàn toàn, phong cách: "${style}".

    YÊU CẦU VỀ NỘI DUNG KỊCH BẢN (CỰC KỲ QUAN TRỌNG):
    1. Kịch bản CHỈ bao gồm lời thoại (dialogue) hoặc lời dẫn truyện (narration).
    2. TUYỆT ĐỐI KHÔNG mô tả nhân vật vào nội dung kịch bản (ví dụ: KHÔNG viết "Cô gái xinh đẹp nói...", "Mặc áo đỏ...").
    3. TUYỆT ĐỐI KHÔNG mô tả bối cảnh vào nội dung kịch bản (ví dụ: KHÔNG viết "Trong căn phòng...", "Dưới ánh nắng...").
    4. TUYỆT ĐỐI KHÔNG viết các ghi chú hành động hoặc cảm xúc trong ngoặc (ví dụ: KHÔNG viết "(cười)", "(khóc)", "(đi bộ)").
    5. Nội dung kịch bản phải thuần túy là câu nói tự nhiên.

    THÔNG TIN THAM KHẢO (Dùng để định hướng nội dung nhưng KHÔNG viết vào kịch bản):
    - Giới tính nhân vật chính: ${gender}.
    - Mô tả nhân vật: ${charDesc}.
    - Ghi chú bối cảnh: ${contextNote}.

    YÊU CẦU NGÔN NGỮ:
    - Vùng miền: ${voice}.
    ${dialectInstruction}
    - Xưng hô "mình", "em", "mình" một cách tự nhiên tùy theo ngữ cảnh POV.

    YÊU CẦU CẤU TRÚC:
    - Chia kịch bản thành đúng ${count} đoạn nhỏ.
    - Mỗi đoạn từ 150 đến 190 ký tự.
    - Trả về kết quả dưới dạng một mảng JSON các chuỗi ký tự.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { parts: [{ text: prompt }] },
      config: { 
        responseMimeType: "application/json",
        responseSchema: { type: Type.ARRAY, items: { type: Type.STRING } }
      }
    });

    return JSON.parse(cleanJsonResponse(response.text || '[]'));
  } catch (e) {
    console.error("Parse script error", e);
    return [];
  }
};

export const generatePovImage = async (
  script: string, 
  facePart: any | null, 
  gender: string, 
  charDesc: string,
  regenNote: string = "",
  imageStyle: 'Realistic' | '3D' = 'Realistic'
): Promise<string> => {
  const ai = getAiClient();
  const modelId = "gemini-2.5-flash-image";
  const is3D = imageStyle === '3D';

  const baseStyle = is3D 
    ? "3D Animation Pixar/Disney style, vibrant colors, expressive 3D character design, high-quality CGI."
    : "Photorealistic RAW PHOTO, 8k resolution, authentic textures, cinematic lighting.";

  const faceInstruction = facePart 
    ? "Maintain the exact facial features of the person in the provided face reference image." 
    : `Appearance: Vietnamese ${gender}. ${charDesc}`;

  const characterFidelityRule = charDesc ? `
    CRITICAL CHARACTER FIDELITY (MANDATORY):
    - You MUST follow these specific appearance details for the character: "${charDesc}".
    - DO NOT deviate from the described clothing, age, physique, or style.
    - The character must look EXACTLY as described in every detail.
    ${is3D ? "- Translate these details into a cute and stylized 3D character design." : ""}
  ` : "";

  const prompt = `
    ${baseStyle} 9:16 aspect ratio.
    Subject: ${faceInstruction}.
    Action/Scene: "${script}".

    ${characterFidelityRule}

    CRITICAL VISUAL RULES (STRICT NO-TEXT & NO-UI POLICY):
    1. ABSOLUTELY NO TEXT, NO LETTERS, NO NUMBERS, NO CHARACTERS, NO WORDS.
    2. ABSOLUTELY NO ICONS, NO EMOJIS, NO GRAPHICS, NO SYMBOLS, NO BUTTONS.
    3. NO SHOPPING CART ICONS, NO "ADD TO CART" BADGES, NO PRICE TAGS, NO DISCOUNT STICKERS.
    4. NO E-COMMERCE ELEMENTS, NO TIKTOK OVERLAYS, NO USER INTERFACE ELEMENTS.
    5. The background must be CLEAN and FREE of signage, posters, labels, or written words.

    CRITICAL RESTRICTIONS & RULES: 
    1. NO CHILDREN, NO KIDS, NO BABIES. The subject must be an adult.
    2. ${is3D ? "Must look like high-quality 3D CGI." : "Must look like a real photo."}

    MANDATORY: NO TEXT, NO SUBTITLES, NO OVERLAYS.
    ${regenNote ? `Additional Feedback: ${regenNote}` : ""}
  `;

  const parts: any[] = [{ text: prompt }];
  if (facePart) parts.push({ inlineData: facePart });

  try {
    const response = await ai.models.generateContent({
      model: modelId,
      contents: { parts },
      config: { imageConfig: { aspectRatio: "9:16" } }
    });
    const imgPart = response.candidates?.[0]?.content?.parts.find(p => p.inlineData);
    return imgPart ? `data:image/png;base64,${imgPart.inlineData.data}` : "";
  } catch (error) {
    console.error("Image generation failed:", error);
    throw error;
  }
};

export const formatVideoPrompt = async (
  script: string, 
  gender: string, 
  voice: string, 
  charDesc: string, 
  contextNote: string,
  imageStyle: 'Realistic' | '3D' = 'Realistic'
): Promise<string> => {
    const ai = getAiClient();
    const is3D = imageStyle === '3D';
    const voiceTag = voice === 'Miền Bắc' ? 'Northern Vietnamese' : 'Southern Vietnamese';
    const voiceGender = gender === 'Nữ' ? 'Female' : 'Male';

    const systemPrompt = `
    Bạn là chuyên gia viết prompt cho AI Video (VEO-3). Dựa trên kịch bản: "${script}", hãy tạo một prompt video hoàn chỉnh.
    PHONG CÁCH VIDEO: ${is3D ? "3D Animation / CGI Style" : "Photorealistic / Real Life Style"}.

    CẤU TRÚC PHẢI TUÂN THỦ 6 ĐOẠN (VIẾT LIỀM MẠCH TRÊN 1 DÒNG):
    Đoạn 1: Nhân vật & bối cảnh. (Nhân vật người Việt Nam ${gender}, ${charDesc}. ${is3D ? "Phong cách hoạt hình 3D Pixar/Disney." : "Phong cách người thật chân thực."} Video tỉ lệ 9:16).
    Đoạn 2: Hành động & tương tác. (Mô tả hành động cách nhân vật di chuyển, nói chuyện và tương tác tự nhiên, POV).
    Đoạn 3: Góc quay & chuyển động máy. (Sáng tạo các chuyển động máy dạng POV).
    Đoạn 4: Hậu cảnh & đạo cụ. (Mô tả chi tiết background đời thường. Lưu ý bối cảnh/cấm kỵ: ${contextNote}).
    Đoạn 5: Lời thoại (QUAN TRỌNG NHẤT): Sử dụng CHÍNH XÁC nội dung:
    ✨ Model speaks in ${voiceTag} voice (${voiceGender}): "${script}"
    Đoạn 6: Thông số kỹ thuật. (9:16, 4K, ${is3D ? "3D Animation, Masterpiece CGI, 60fps" : "Realistic, Cinematic Lighting, Photorealistic, 60fps"}).

    YÊU CẦU ĐẦU RA: Chỉ trả về 1 dòng văn bản duy nhất.
    `;

    const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: { parts: [{ text: systemPrompt }] }
    });
    return response.text?.trim().replace(/\n/g, ' ') || "";
};

